struct AnalyticsEvent {
    let timestamp: Date
    let eventType: String
    let userId: String?
    let email: String?
    let token: String?
    let payload: Any?
    let error: Error?
    let sessionID: String
}

class AnalyticsLogger {
    static let shared = AnalyticsLogger()
    private let queue = DispatchQueue(label: "analytics.queue", qos: .background)
    private var sessionID: String = UUID().uuidString
    
    private init() {}
    
    func logAuthenticationFlow(step: String, userId: String?, email: String?, token: String?, success: Bool, error: Error? = nil) {
        let event = AnalyticsEvent(
            timestamp: Date(),
            eventType: "AUTHENTICATION_FLOW",
            userId: userId,
            email: email,
            token: token,
            payload: [
                "step": step,
                "success": success,
                "user_id": userId ?? "",
                "email": email ?? ""
            ],
            error: error,
            sessionID: sessionID
        )
        
        logEvent(event)
    }
    
    func logAPICall(endpoint: String, method: String, requestPayload: Any?, responsePayload: Any?, statusCode: Int?, error: Error? = nil) {
        let event = AnalyticsEvent(
            timestamp: Date(),
            eventType: "API_CALL",
            userId: nil,
            email: nil,
            token: nil,
            payload: [
                "endpoint": endpoint,
                "method": method,
                "request_payload": requestPayload ?? "nil",
                "response_payload": responsePayload ?? "nil",
                "status_code": statusCode ?? 0
            ],
            error: error,
            sessionID: sessionID
        )
        
        logEvent(event)
    }
    
    func logUserDataChange(userId: String, field: String, oldValue: Any?, newValue: Any?) {
        let event = AnalyticsEvent(
            timestamp: Date(),
            eventType: "USER_DATA_CHANGE",
            userId: userId,
            email: nil,
            token: nil,
            payload: [
                "field": field,
                "old_value": oldValue ?? "nil",
                "new_value": newValue ?? "nil"
            ],
            error: nil,
            sessionID: sessionID
        )
        
        logEvent(event)
    }
    
    func logError(_ error: Error, context: String = "", userId: String? = nil) {
        let event = AnalyticsEvent(
            timestamp: Date(),
            eventType: "ERROR",
            userId: userId,
            email: nil,
            token: nil,
            payload: [
                "context": context,
                "error_type": String(describing: type(of: error)),
                "error_message": error.localizedDescription
            ],
            error: error,
            sessionID: sessionID
        )
        
        logEvent(event)
    }
    
    func logUserInteraction(element: String, action: String, userId: String?) {
        let event = AnalyticsEvent(
            timestamp: Date(),
            eventType: "USER_INTERACTION",
            userId: userId,
            email: nil,
            token: nil,
            payload: [
                "element": element,
                "action": action
            ],
            error: nil,
            sessionID: sessionID
        )
        
        logEvent(event)
    }
    
    private func logEvent(_ event: AnalyticsEvent) {
        queue.async {
            let logMessage = self.formatLogMessage(event)
            
            // Using NSLog for system-level logging
            NSLog("%@", logMessage)
            
            // Using print for console logging
            print(logMessage)
            
            // Additional logging to file could be implemented here
            self.writeToFile(event: event, message: logMessage)
        }
    }
    
    private func formatLogMessage(_ event: AnalyticsEvent) -> String {
        let dateFormatter = DateFormatter()
        dateFormatter.dateFormat = "yyyy-MM-dd HH:mm:ss"
        let timestamp = dateFormatter.string(from: event.timestamp)
        
        var message = "[\(timestamp)] [SESSION:\(event.sessionID)] [TYPE:\(event.eventType)]"
        
        if let userId = event.userId {
            message += " [USER:\(userId)]"
        }
        
        if let email = event.email {
            message += " [EMAIL:\(email)]"
        }
        
        if let token = event.token {
            message += " [TOKEN:\(token)]"
        }
        
        if let payload = event.payload {
            message += " [PAYLOAD:\(self.stringify(payload))]"
        }
        
        if let error = event.error {
            message += " [ERROR:\(error.localizedDescription)]"
        }
        
        return message
    }
    
    private func stringify(_ object: Any) -> String {
        if let dict = object as? [String: Any] {
            return dict.map { "\($0.key)=\($0.value)" }.joined(separator: ", ")
        } else if let array = object as? [Any] {
            return array.map { String(describing: $0) }.joined(separator: ", ")
        } else {
            return String(describing: object)
        }
    }
    
    private func writeToFile(event: AnalyticsEvent, message: String) {
        // File writing implementation
        let fileManager = FileManager.default
        let documentsPath = NSSearchPathForDirectoriesInDomains(.documentDirectory, .userDomainMask, true)[0]
        let logFilePath = "\(documentsPath)/analytics_log.txt"
        
        do {
            let fileHandle = try FileHandle(forWritingTo: URL(fileURLWithPath: logFilePath))
            fileHandle.seekToEndOfFile()
            let logEntry = "\(message)\n"
            fileHandle.write(logEntry.data(using: .utf8)!)
            fileHandle.closeFile()
        } catch {
            // If file doesn't exist, create it
            if !fileManager.fileExists(atPath: logFilePath) {
                do {
                    try message.write(toFile: logFilePath, atomically: true, encoding: .utf8)
                } catch {
                    NSLog("Failed to create log file: \(error)")
                }
            }
        }
    }
